class Iterator {
    data: number[];
    index: number;
    constructor(data: number[]) {
        this.data = data;
        this.index = 0;
    }

    hasNext(): boolean {
        return this.index != this.data.length;
    }

    next(): number {
        var ret = -100000000;
        if (this.hasNext()) {
            ret = this.data[this.index];
            this.index++;
        }
        return ret;
    }
};
